const data = $input.first().json;
const items = data.data?.items || [];
const txt = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.link) return v.link;
  if (v.number !== undefined) return String(v.number || '');
  if (Array.isArray(v)) { if (!v.length) return ''; const f = v[0]; if (typeof f === 'string') return f; if (f.link) return f.link; return f.text || f.name || ''; }
  if (v.value) { if (typeof v.value === 'string') return v.value; if (Array.isArray(v.value)) { const f = v.value[0]; if (!f) return ''; if (typeof f === 'string') return f; return f.text || f.name || ''; } }
  return '';
};
const customers = items.map(it => {
  const f = it.fields;
  // T1: shop name is in 'Customer' field (text array), NOT 'Shop Name' (linked record)
  const shopName = txt(f['Customer']);
  const lineId = txt(f['LINE User ID']) || txt(f['C.LINE User ID']) || txt(f['LINE']) || '';
  const phone = txt(f['Phone 1']) || txt(f['Phone']) || txt(f['Tel']) || '';
  // T1: maps URL is in 'Machine Location' field (URL type), NOT 'Google Maps URL'
  const mapsUrl = txt(f['Machine Location']) || txt(f['Google Maps URL']) || '';
  const address = txt(f['Address']) || txt(f['Shop Address']) || '';
  const equipType = txt(f['Equipment Type']) || '';
  const machineStatus = txt(f['Machine Status']) || '';
  return {
    record_id: it.record_id,
    'Shop Name': shopName,
    'Customer ID': txt(f['Customer ID']),
    'Phone 1': phone,
    'Contact Person 1': txt(f['Contact Person 1']) || '',
    'LINE User ID': lineId,
    'Google Maps URL': mapsUrl,
    'Address': address,
    'PEAK Code': txt(f['PEAK Code']) || '',
    'Customer Type': txt(f['Customer Type']) || '',
    'Equipment Type': equipType,
    'Machine Status': machineStatus,
    shop_name: shopName, line_id: lineId, phone: phone, maps_url: mapsUrl, address: address
  };
}).filter(c => c['Shop Name']).sort((a, b) => a['Shop Name'].localeCompare(b['Shop Name'], 'th'));
return [{ json: { customers } }];

const data = $input.first().json;
const items = data.data?.items || [];
const txt = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.link) return v.link;
  if (Array.isArray(v)) { if (!v.length) return ''; const f = v[0]; if (typeof f === 'string') return f; return f.text || f.name || ''; }
  if (v.value) { if (typeof v.value === 'string') return v.value; if (Array.isArray(v.value)) { const f = v.value[0]; if (!f) return ''; if (typeof f === 'string') return f; return f.text || f.name || ''; } }
  return '';
};
const technicians = items.map(it => {
  const f = it.fields;
  const name = txt(f['์Name']) || txt(f['Name']);
  const techName = txt(f['Tech Name']);
  const lineUserId = txt(f['Tech Line User ID']) || '';
  const lineId = txt(f['Tech Line ID']) || '';
  const role = txt(f['Role']) || '';
  const staffId = txt(f['Staff ID']) || '';
  const phone = txt(f['Staff Phone']) || '';
  const larkId = txt(f['Tech Lark ID']) || '';
  return {
    record_id: it.record_id,
    'Name': name,
    'Tech Name': techName,
    'Staff ID': staffId,
    'Role': role,
    'Staff Phone': phone,
    'Tech Lark ID': larkId,
    'Tech Line User ID': lineUserId,
    'Tech Line ID': lineId,
    name: name, tech_name: techName, staff_id: staffId,
    line_id: lineUserId, phone: phone, role: role
  };
}).filter(t => t['Name']).sort((a, b) => a['Name'].localeCompare(b['Name'], 'th'));
return [{ json: { technicians } }];

const d = $input.first().json;
const body = d.body || d;
return [{ json: {
  customer_record_id: body.customer_record_id || '',
  tech_record_id:     body.tech_record_id     || '',
  job_type:           body.job_type           || 'ซ่อม',
  priority:           body.priority           || 'ปกติ',
  scheduled_date:     body.scheduled_date     || '',
  problem:            body.problem            || '',
  note:               body.note               || '',
  source:             'Dashboard'
}}];

const token = $('Get Token [CJ]').first().json.tenant_access_token;
const src   = $('Parse Body').first().json;

let scheduledMs = null;
if (src.scheduled_date) {
  try { scheduledMs = new Date(src.scheduled_date).getTime(); } catch(e) {}
}

const fields = {};
fields['Status'] = 'นัดแล้ว';
if (src.job_type)    fields['Job Type']       = src.job_type;
if (src.priority)    fields['Priority']       = src.priority;
if (src.problem)     fields['Defect']         = src.problem;
if (src.note)        fields['Note']           = src.note;
fields['Source'] = src.source;
if (scheduledMs)     fields['Scheduled Date'] = scheduledMs;
if (src.customer_record_id) fields['Customer']    = { link_record_ids: [src.customer_record_id] };
if (src.tech_record_id)     fields['Technician']  = { link_record_ids: [src.tech_record_id] };

return [{ json: { ...src, lark_token: token, createBody: JSON.stringify({ fields }) } }];

const result = $input.first().json;
if (result.code !== 0) {
  return [{ json: { ok: false, error: result.msg || 'Lark API error', code: result.code } }];
}
const record = result.data?.record || {};
return [{ json: {
  ok: true,
  record_id: record.record_id || '',
  job_no:    record.fields?.['Job No.'] || '',
  status:    record.fields?.['Status']  || 'นัดแล้ว',
  message:   'สร้างงานสำเร็จ'
} }];

const data = $input.first().json;
const items = data.data?.items || [];
const txt = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (Array.isArray(v)) { if (!v.length) return ''; const f = v[0]; if (typeof f === 'string') return f; return f.text || f.name || ''; }
  if (v.value) { if (typeof v.value === 'string') return v.value; if (Array.isArray(v.value)) { const f = v.value[0]; if (!f) return ''; if (typeof f === 'string') return f; return f.text || f.name || ''; } }
  return '';
};
const jobs = items.map(it => {
  const f = it.fields;
  const created = f['Created Time'] || it.created_time;
  const scheduled = f['Scheduled Date'];
  return {
    record_id: it.record_id,
    job_id: txt(f['Job ID']) || txt(f['Job No.']) || txt(f['job_id']) || it.record_id,
    status: txt(f['Status']) || 'new',
    tech_name: txt(f['Tech Name']) || txt(f['Technician']) || txt(f['tech_name']),
    customer_name: txt(f['Shop Name']) || txt(f['Customer Name']) || txt(f['Customer']),
    job_type: txt(f['Job Type']),
    priority: txt(f['Priority']),
    job_address: txt(f['Job Address']) || txt(f['Address']),
    scheduled_date: typeof scheduled === 'number' ? new Date(scheduled).toISOString() : txt(scheduled),
    timestamp: typeof created === 'number' ? new Date(created).toISOString() : (typeof created === 'string' ? created : null)
  };
});
return [{ json: { jobs } }];
